class Solution:
    def matrixSum(self, nums):
        mat = [list(row) for row in nums]
        cols = len(mat[0]) if mat else 0
        score = 0
        for _ in range(cols):
            removed = []
            for row in mat:
                if not row:
                    continue
                mx = max(row)
                row.remove(mx)
                removed.append(mx)
            if removed:
                score += max(removed)
        return score

