class Solution:
    def matrixSum(self, nums):
        rows = [sorted(row) for row in nums]
        n = max(len(row) for row in rows) if rows else 0
        score = 0
        for j in range(n):
            best = 0
            for row in rows:
                idx = len(row) - 1 - j
                if idx >= 0 and row[idx] > best:
                    best = row[idx]
            score += best
        return score

