var matrixSum = function(nums) {
    const rows = nums.map(row => [...row].sort((a, b) => a - b));
    const n = rows.reduce((m, row) => Math.max(m, row.length), 0);
    let score = 0;
    for (let j = 0; j < n; j++) {
        let best = 0;
        for (const row of rows) {
            const idx = row.length - 1 - j;
            if (idx >= 0 && row[idx] > best) best = row[idx];
        }
        score += best;
    }
    return score;
};
